(game "Annoying Sawfish Of Piety"
    (players 2)
    (equipment
        (board (square 5))
    )

    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination empty)
                    (result
                        (not
                            (and
                                (exists
                                    (adjacent
                                        (occupied opponent)
                                        direction:any
                                    )
                                )
                                (exists
                                    (adjacent
                                        empty
                                        direction:any
                                    )
                                )
                            )
                        )
                    )
                )
            )
        )

        (end
            (if
                (not
                    (exists
                        (and
                            empty
                            (or
                                (adjacent
                                    (occupied mover)
                                    direction:any
                                )
                                (adjacent
                                    empty
                                    direction:any
                                )
                            )
                        )
                    )
                )
                (mover win)
            )
            (if (full_board) (draw))
        )
    )
)

